#include <bits/stdc++.h>
using namespace std;
int di[4][2]={{0,1},{1,0},{0,-1},{-1,0}};
int n,m,g[101][101],step[101][101],pdi[101][101],sx,sy,tx,ty;
bool b[101][101];
queue<int> qx,qy;
int main(){
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            int p;
            cin>>p;
            if(p)
                g[i-1][j-1]=g[i][j]=g[i-1][j]=g[i][j-1]=1;
        }
    char tmp;
    cin>>sx>>sy>>tx>>ty>>tmp;
    if(tmp=='E')
        pdi[sx][sy]=0;
    else if(tmp=='S')
        pdi[sx][sy]=1;
    else if(tmp=='W')
        pdi[sx][sy]=2;
    else
        pdi[sx][sy]=3;
    memset(step,127,sizeof(step));
    step[sx][sy]=0,b[sx][sy]=1;
    qx.push(sx),qy.push(sy);
    /*for(int i=0;i<=n;i++){
    	for(int j=0;j<=m;j++)
   			cout<<setw(4)<<g[i][j];
   		cout<<endl;
	}
	cout<<endl;*/
    while(qx.size()){
        int fx=qx.front(),fy=qy.front();
        b[fx][fy]=0;
        qx.pop();
        qy.pop();
        for(int i=0;i<4;i++)
            for(int len=1;len<=3;len++){
                int xx=fx+di[i][0]*len,yy=fy+di[i][1]*len;
                if(!(xx>0 && xx<n && yy>0 && yy<m && !g[xx][yy]))
                	break;
                if(step[xx][yy]>step[fx][fy]+min(abs(pdi[fx][fy]-i),4-abs(pdi[fx][fy]-i))+1){
                    step[xx][yy]=step[fx][fy]+min(abs(pdi[fx][fy]-i),4-abs(pdi[fx][fy]-i))+1;
                    pdi[xx][yy]=i;
                    if(!b[xx][yy])
                        b[xx][yy]=1,qx.push(xx),qy.push(yy);
                }
            }
        /*for(int i=0;i<=n;i++){
	    	for(int j=0;j<=m;j++)
    			cout<<setw(4)<<(step[i][j]<(1<<30)? step[i][j]:-1);
    		cout<<endl;
		}
		cout<<endl;*/
    }
    if(step[tx][ty]<(1<<30))
        cout<<step[tx][ty];
    else
        cout<<-1;
    return 0;
}
